#include<cstdio>
#include<iostream>
#include<vector>
#include<unordered_map>
#include<map>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=Nxt[c])
using std::string;using std::cin; using std::vector; using std::pair;
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
struct Pair
{
	int x,y;inline Pair(int X=0,int Y=0){x=X;y=Y;}
	inline bool operator < (const Pair &Q)const {return x==Q.x?y<Q.y:x<Q.x;}
};
const int N=77790;int n,m,acd[N],ans,nxt[N],in[N],ou[N],st[N],ed[N],S1[N],lst[N],opt[N],V[N];bool usd[N];
std::map<Pair, vector<Pair> > mp;std::map<Pair,vector<int> > up[2];std::unordered_map<string,int> Idx;
namespace MF
{
	const int N=3e5+10,M=2e6+10,INF=0x3f3f3f3f;
	int head[N],des[M],Nxt[M],cgt=1,s,t,S,dep[N],que[N],cap[M],H,T,jud[N];bool vis[N];
	inline void Clear(){memset(head,0,(S+2)<<2);cgt=1;S=0;}
	inline void ins(const int &x,const int &y,const int &c=1)
	{
		if(!x||!y)return;
		Nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=c;
		Nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
	}
	inline bool bfs()
	{
		memset(dep,0,(S+2)<<2);dep[que[H=T=0]=s]=1;
		while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
	}
	inline int dfs(const int &u=s,int in=INF)
	{
		if(u==t)return in;int out=0;grep(u,i)
		{
			int v=des[i];if(cap[i]&&dep[v]==dep[u]+1)
			{
				int tmp=dfs(v,cap[i]<in?cap[i]:in);
				out+=tmp;cap[i]-=tmp;cap[i^1]+=tmp;if(!(in-=tmp))break;
			}
		}
		return out?out:dep[u]=0;
	}
	inline int dinic(){int res=0;while(bfs())res+=dfs();return res;}
	inline void getAns()
	{
		rep(1,m,i)
		{
			if(!nxt[i])
			{
				int &u=nxt[i]=in[i]; grep(u,i)if(!cap[i]&&jud[des[i]]==-1)u=des[i];
				if(!jud[u])u=0;else grep(u,i)if(!cap[i]&&jud[des[i]]){u=jud[des[i]];cap[i]=1;break;}
			}
			lst[nxt[i]]=i;
		}
		rep(1,m,i)if(!lst[i]&&!vis[i])for(int u=i;u;u=nxt[u])vis[u]=true;
		rep(1,m,i)if(!vis[i]&&!usd[i]&&lst[i]&&~opt[i])
		{
			vis[i]=true;for(int u=nxt[i];u!=i;u=nxt[u])vis[u]=true;
			if(opt[i])
			{
				int x=acd[V[i]],y=lst[x],z=nxt[i];
				lst[x]=i;nxt[i]=x;lst[z]=y;nxt[y]=z;
			}
			else
			{
				int x=acd[V[i]],y=nxt[x],z=lst[i];
				lst[i]=x;nxt[x]=i;nxt[z]=y;lst[y]=z;
			}
			
		}
		rep(1,m,i)if(!lst[i]&&vis[i])for(int u=i;u;u=nxt[u])vis[u]=false,print(u),putchar(' ');putchar('\n');
	}
}
using MF::ins;using MF::S; using MF::jud;using MF::vis;using MF::s;using MF::t;

inline void Clear()
{
	Idx.clear();up[0].clear();up[1].clear();mp.clear();
	memset(jud,0,(S+2)<<2);memset(vis,0,S+2);MF::Clear();ans=0;s=++S;t=++S;
	memset(nxt,0,(m+2)<<2);memset(acd,0,(n+2)<<2);memset(ou,0,(m+2)<<2);
	memset(lst,0,(m+2)<<2);memset(opt,0,(m+2)<<2);memset(in,0,(m+2)<<2);
}
inline void Solve()
{
	Clear();cin>>n>>m;rep(1,n,i){string s;cin>>s;Idx[s]=i;st[i]=++S;ed[i]=++S;jud[S]=jud[S-1]=-1;}
	rep(1,m,i)
	{
		string s1,s2,s3;cin>>s1>>s2>>s3;S1[i]=Idx[s1];
		if((s3=="loushang"||s3=="louxia")&&Idx.count(s2)){up[opt[i]=s3=="loushang"][Pair(S1[i],V[i]=Idx[s2])].push_back(i);}
		else {opt[i]=-1;acd[S1[i]]=i;mp[Pair(S1[i],S1[i])].push_back(Pair(i,i));}
	}
	for(pair< const Pair,vector<int> > &v : up[1])
	{
		vector<int> &x=v.second,&y=up[0][Pair(v.first.y,v.first.x)];
		while(x.size()&&y.size())
		{
			int tx=*prev(x.end()),ty=*prev(y.end());x.pop_back();y.pop_back();
			mp[v.first].push_back(Pair(tx,ty));ans+=2;nxt[tx]=ty;usd[tx]=usd[ty]=true;
		}
	}
	for(pair< const Pair,vector<int> > v: up[1])for(int w:v.second){ou[w]=++S;ins(in[w]=++S,st[v.first.y]);}
	for(pair< const Pair,vector<int> > v: up[0])for(int w:v.second){in[w]=++S;ins(ed[v.first.y],ou[w]=++S);}
	for(pair< const Pair,vector<Pair> > v: mp)for(Pair w:v.second)in[w.y]=++S,ou[w.x]=++S;
	rep(1,m,i)
	{
		ins(s,in[i]);ins(ou[i],t);jud[ou[i]]=i;
		ins(st[S1[i]],ou[i]);ins(in[i],ed[S1[i]]);
	}
	print(ans+MF::dinic());putchar('\n');MF::getAns();return;
}
int main()
{
	std::ios::sync_with_stdio(false);cin.tie(0);
	int T;cin>>T;while(T--)Solve();return 0;
}
